                // 초기 속도: 200~300 픽셀/초
                initialSpeed: 200 + getRandom().next() * 100,
                // 회전 속도: -360~360도/초
                rotationSpeed: -360 + getRandom().next() * 720,
                // 중력 가속도: 980 픽셀/초^2 (물리학적 중력과 유사)
                gravity: 980,
                // 애니메이션 지속 시간: 0.8~1.2초
                duration: 400 + getRandom().next() * 400,
                // 타임스탬프 초기화
                startTime: null,
                // 위치 및 회전 추적
                x: 0,
